+        // "git add . && echo done" (bypass via shell chaining). Also accept an
+        // optional quote pair around `.` so `git add '.'` / `git add "."` are
+        // caught — shell-quoted `.` evaluates to `.` in the exec and stages
+        // everything identically.
         destructive_pattern!(
             "add-all-dot",
-            r"git\b.*?\badd\s+\.(?:\s|$)",
+            r#"git\b.*?\badd\s+['"]?\.['"]?(?:\s|$)"#,
